package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithAllowMissingColumnNames_noArg() {
        CSVFormat original = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        CSVFormat updated = original.withAllowMissingColumnNames();

        assertNotNull(updated);
        assertTrue(updated.getAllowMissingColumnNames());
        assertNotSame(original, updated);

        // Ensure other properties remain unchanged
        assertEquals(original.getDelimiter(), updated.getDelimiter());
        assertEquals(original.getQuoteCharacter(), updated.getQuoteCharacter());
        assertEquals(original.getRecordSeparator(), updated.getRecordSeparator());
    }

    @Test
    public void testWithAllowMissingColumnNames_withTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    public void testWithAllowMissingColumnNames_withFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }

}
